import { describe, it, expect } from 'vitest';
import { matchesBreakpoint, BREAKPOINT_KEYWORDS } from '../../lib/breakpoint-keywords.js';

describe('matchesBreakpoint', () => {
  it('returns false on empty subject', () => {
    expect(matchesBreakpoint('')).toBe(false);
  });

  it('matches "merged" case-insensitively', () => {
    expect(matchesBreakpoint('MERGED PR #123')).toBe(true);
    expect(matchesBreakpoint('feat: merged into main')).toBe(true);
  });

  it('matches "Merge pull request" GitHub auto-subject', () => {
    expect(matchesBreakpoint('Merge pull request #42 from foo/bar')).toBe(true);
  });

  it('matches "Closes #" / "Fixes #" / "Resolves #"', () => {
    expect(matchesBreakpoint('feat: add thing closes #99')).toBe(true);
    expect(matchesBreakpoint('Fixes #1')).toBe(true);
    expect(matchesBreakpoint('Resolves#5')).toBe(true);
  });

  it('matches release commit subjects', () => {
    expect(matchesBreakpoint('chore(main): release 7.71.0')).toBe(true);
    expect(matchesBreakpoint('chore: release v2')).toBe(true);
  });

  it('does NOT match generic conventional-commit prefixes alone', () => {
    expect(matchesBreakpoint('feat(thing): add helper')).toBe(false);
    expect(matchesBreakpoint('fix(parser): handle edge case')).toBe(false);
    expect(matchesBreakpoint('chore(deps): bump foo')).toBe(false);
    expect(matchesBreakpoint('refactor: split module')).toBe(false);
  });

  it('does not match arbitrary text', () => {
    expect(matchesBreakpoint('asdf random words')).toBe(false);
    expect(matchesBreakpoint('wip on something')).toBe(false);
  });

  it('exposes a non-empty keyword list', () => {
    expect(BREAKPOINT_KEYWORDS.length).toBeGreaterThan(5);
    expect(BREAKPOINT_KEYWORDS.every(k => k === k.toLowerCase())).toBe(true);
  });
});
